  ('judicial-57112235-moex-00337', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', 'A的妻子B懷疑A有外遇，乃有償委託甲在A經常使用的汽車上裝設GPS，藉此蒐集A之行蹤，依實務 見解，甲的行為要如何論罪？', '["構成刑法第315條之1的無故以電磁紀錄竊錄他人非公開活動之犯罪", "構成刑法第318條之1的無故洩漏因利用電腦知悉或持有他人秘密之犯罪", "構成刑法第317條的無故洩漏依契約有守因業務知悉工商秘密義務之犯罪", "構成刑法第316條的無故洩漏因業務知悉或持有他人秘密之犯罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00338', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何種情形，無法成立加重竊盜罪？', '["甲夥同乙竊取停放在路邊的機車", "甲利用深夜潛入A宅竊取財物", "甲、乙、丙三人組成扒竊集團在西門町扒走觀光客A的皮夾", "甲在公車上扒走乘客A包包內的最新款手機"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
