  ('judicial-57112235-moex-00340', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲於計程車休息站附近欲趁機行竊，見計程車駕駛乙上廁所的空檔，鑽進乙車準備拿走鈔票時，正好乙走 出廁所發現甲正在偷錢。甲拿走紙鈔，欲逃離現場時，被乙發現，甲拾起路邊的木棍毆打乙，乙被毆後倒 臥在地，甲即趕緊離開現場。依實務見解，下列敘述何者正確？', '["甲應成立第328條強盜罪", "甲應成立第325條搶奪罪", "甲應成立第329條準強盜罪", "甲應成立第335條侵占罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00341', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲為家電雜貨公司倉庫庫藏管理人員，因急需用錢，夥同友人乙一同將甫進貨的電器，由乙用貨車載走， 一同在網路上折價轉賣，換取現金週轉。依實務見解，乙應如何論罪？', '["成立刑法第339條詐欺罪之共同正犯", "成立刑法第320條竊盜罪之共同正犯", "成立刑法第336條業務侵占罪之共同正犯", "成立刑法第335條普通侵占罪之共同正犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00342', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲前往臺北謀職不順，走投無路，乃向同鄉乙訴苦。乙表示，可以貸予100萬元救急，限期一個月歸還， 且毋庸利息，只是需要預扣20萬元手續費與逾期不還的違約金20萬元。甲急需用錢，乃向乙借款。關於 乙之行為，下列何者正確？', '["民事借貸，乙不成立犯罪", "乙成立詐欺罪", "乙成立背信罪", "乙成立重利罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00343', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲竊得金飾，以金飾與知情之乙互易手機，甲再將該手機贈與知情之丙。下列敘述何者正確？', '["甲成立竊盜罪及贓物罪；乙成立贓物罪；丙不成立贓物罪", "甲成立竊盜罪；乙成立贓物罪；丙不成立贓物罪", "甲成立竊盜罪及贓物罪；乙丙成立贓物罪", "甲成立竊盜罪；乙丙成立贓物罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
